# Use awk to do the topological sort efficiently
awk '
BEGIN { FS=":" }
{
    target = $1
    gsub(/^[[:space:]]+|[[:space:]]+$/, "", target)
    if (target == "") next

    dep_str = $2
    gsub(/^[[:space:]]+|[[:space:]]+$/, "", dep_str)

    # Track all targets
    targets[target] = 1

    # Parse deps
    n = split(dep_str, darr, /[[:space:]]+/)
    in_degree[target] += 0  # ensure entry exists
    for (i = 1; i <= n; i++) {
        if (darr[i] != "") {
            deps[target, darr[i]] = 1
            # record that target depends on darr[i]
            in_degree[target]++
            targets[darr[i]] = 1
            # record reverse: darr[i] -> target (for adjacency)
            dependents[darr[i]] = dependents[darr[i]] " " target
        }
    }
}
END {
    # Initialize in_degree for all targets
    for (t in targets) {
        if (!(t in in_degree)) in_degree[t] = 0
    }

    # Kahns algorithm
    # Find all with in_degree 0
    qlen = 0
    for (t in targets) {
        if (in_degree[t] == 0) {
            queue[qlen++] = t
        }
    }

    olen = 0
    qi = 0
    while (qi < qlen) {
        cur = queue[qi++]
        order[olen++] = cur

        # For each dependent of cur
        n2 = split(dependents[cur], dep_arr2, /[[:space:]]+/)
        for (j = 1; j <= n2; j++) {
            d = dep_arr2[j]
            if (d == "") continue
            in_degree[d]--
            if (in_degree[d] == 0) {
                queue[qlen++] = d
            }
        }
    }

    # Print build order
    for (i = 0; i < olen; i++) {
        print order[i]
    }
}
' /project/deps.txt

